import { SupportTicketActions } from "@/components/admin/support-ticket-actions";

export const metadata = {
  title: "Support Tickets — Admin",
};

type TicketStatus = "open" | "in_progress" | "resolved" | "closed";

export default async function AdminSupportPage({
  searchParams,
}: {
  searchParams: { status?: string };
}) {
  await requireAdmin();

  const statusFilter = (searchParams.status as TicketStatus) || "open";

  // Fetch tickets with filtering
  const tickets = await prisma.supportTicket.findMany({
    where: statusFilter === "open" 
      ? { status: statusFilter }
      : statusFilter 
      ? { status: statusFilter }
      : undefined,
    orderBy: {
      createdAt: "desc",
    },
  });

  // Get ticket counts by status
  const statusCounts = await prisma.supportTicket.groupBy({
    by: ["status"],
    _count: true,
  });

  const counts: Record<string, number> = {
    open: 0,
    in_progress: 0,
    resolved: 0,
    closed: 0,
  };

  statusCounts.forEach(({ status, _count }) => {
    counts[status] = _count;
  });

  const getStatusColor = (status: string) => {
    switch (status) {
      case "open":
        return "bg-red-500/10 text-red-400 border-red-500/30";
      case "in_progress":
        return "bg-blue-500/10 text-blue-400 border-blue-500/30";
      case "resolved":
        return "bg-green-500/10 text-green-400 border-green-500/30";
      case "closed":
        return "bg-zinc-500/10 text-zinc-400 border-zinc-500/30";
      default:
        return "bg-zinc-500/10 text-zinc-400 border-zinc-500/30";
    }
  };

  const getStatusIcon = (status: string) => {
