import { NextRequest, NextResponse } from "next/server";
import { login } from "@/lib/auth";
import { checkRateLimit, getIP } from "@/lib/rate-limit";
import { prisma } from "@/lib/db";

// Allow up to 30s for bcrypt + DB + transient retry before Vercel times out.
export const maxDuration = 30;

export async function POST(request: NextRequest) {
  const startTime = Date.now();
  console.log(`[API] POST /api/auth/signin: Request received`);

  // Rate limit: 5 attempts per 10 minutes per IP
  const ip = getIP(request);
  const rl = checkRateLimit(`signin:${ip}`, 5, 10 * 60 * 1000);
  if (!rl.allowed) {
    return NextResponse.json(
      { error: "Too many attempts. Please try again later." },
      { status: 429, headers: { "Retry-After": String(rl.retryAfterSeconds) } }
    );
  }

  try {
    const { email, password } = await request.json();

    if (!email || !password) {
      return NextResponse.json(
        { error: "Email and password are required" },
        { status: 400 }
      );
    }

    // Attempt login — retry once on transient DB connection errors (Vercel cold start).
    let result = await login(email, password).catch(async (firstErr: unknown) => {
      const msg = firstErr instanceof Error ? firstErr.message : String(firstErr);
      const isTransient =
        msg.includes("Can't reach database") ||
        msg.includes("Connection refused") ||
        msg.includes("pool timeout") ||
        msg.includes("ECONNREFUSED") ||
        msg.includes("P1001") ||
        msg.includes("P1008") ||
        msg.includes("P2024");
      console.error(`[API] signin: first attempt failed${isTransient ? " (transient, retrying)" : ""}:`, msg);
      if (isTransient) {
        await new Promise((r) => setTimeout(r, 600));
        return login(email, password);
      }
      throw firstErr;
    });

    if (!result.success) {
      const elapsed = Date.now() - startTime;
      console.log(`[API] POST /api/auth/signin: Login failed [${elapsed}ms]: ${result.error}`);
      return NextResponse.json(
        { error: result.error || "Login failed" },
        { status: 401 }
      );
    }

    const elapsed = Date.now() - startTime;
    console.log(`[API] POST /api/auth/signin: SUCCESS role=${result.role} hasPurchase=${result.hasPurchase} [${elapsed}ms]`);

    // For family plan users, we need to know profile count to route correctly.
    let isFamily = false;
    let profileCount = 0;
    if (result.userId && result.role === "student") {
      try {
        const userData = await prisma.user.findUnique({
          where: { id: result.userId },
          select: {
            planType: true,
            _count: { select: { learnerProfiles: true } },
          },
        });
        isFamily = userData?.planType === "family";
        profileCount = userData?._count?.learnerProfiles ?? 0;
      } catch (err) {
        // Non-fatal: can't determine family status, default to individual routing.
        console.error(`[API] POST /api/auth/signin: family-check DB query failed:`, err);
      }
    }

    return NextResponse.json({
      success: true,
      role: result.role,
      hasPurchase: result.hasPurchase,
      isFamily,
      profileCount,
    });
  } catch (error) {
    const elapsed = Date.now() - startTime;
    const msg   = error instanceof Error ? error.message : String(error);
    const code  = (error as { code?: string }).code ?? "unknown";
    const meta  = (error as { meta?: unknown }).meta;
    console.error(`[API] POST /api/auth/signin: UNHANDLED ERROR [${elapsed}ms] code=${code}:`, msg, meta ?? "");
    return NextResponse.json(
      { error: "Something went wrong. Please try again." },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { requireStudent } from "@/lib/auth";
import { getPartById } from "@/lib/content";
import {
  readBriefing,
  readStatementOfFacts,
  readStudyGuide,
  readReport,
  getSlideFiles,
  getInfographicFilename,
  mindmapExists,
  readQuiz,
  readFlashcards,
  getPartAssetUrls,
} from "@/lib/files";
import { getR2PublicUrl, getR2AssetUrl } from "@/lib/r2";

export async function GET(req: NextRequest) {
  if (process.env.NODE_ENV === "production") {
    return NextResponse.json({ error: "Not available" }, { status: 403 });
  }

  try {
    const user = await requireStudent();

    const searchParams = req.nextUrl.searchParams;
    const partNum = parseInt(searchParams.get("partNumber") || "1");

    const partBase = getPartById(`part-${partNum}`);
    if (!partBase) {
      return NextResponse.json({ error: "Part not found" }, { status: 404 });
    }

    console.log(`\n=== DEBUG: Loading content for Part ${partNum} ===`);

    // Load all assets
    const [
      briefingText,
      statementOfFactsText,
      studyGuideText,
      reportText,
      quizData,
      flashcards,
      slidesPresentedFiles,
      slidesDetailedFiles,
      slidesFactsFiles,
      infConcise,
      infStandard,
      infBento,
      hasMindmap,
      assetUrls,
    ] = await Promise.all([
      readBriefing(partNum),
      readStatementOfFacts(partNum),
      readStudyGuide(partNum),
      readReport(partNum),
      readQuiz(partNum),
      readFlashcards(partNum),
      getSlideFiles(partNum, "presented"),
      getSlideFiles(partNum, "detailed"),
      getSlideFiles(partNum, "facts"),
      getInfographicFilename(partNum, "Concise"),
      getInfographicFilename(partNum, "Standard"),
      getInfographicFilename(partNum, "Bento Grid"),
      mindmapExists(partNum),
      getPartAssetUrls(partNum),
    ]);

    const diagnostics = {
      partNumber: partNum,
      partTitle: partBase.title,
      environment: {
        R2_BUCKET: !!process.env.R2_BUCKET,
        R2_ACCESS_KEY_ID: !!process.env.R2_ACCESS_KEY_ID,
        R2_SECRET_ACCESS_KEY: !!process.env.R2_SECRET_ACCESS_KEY,
        R2_PUBLIC_URL: !!process.env.R2_PUBLIC_URL,
        R2_ACCOUNT_ID: !!process.env.R2_ACCOUNT_ID,
        USE_R2: process.env.R2_BUCKET && process.env.R2_ACCESS_KEY_ID,
      },
      content: {
        briefing: {
          exists: !!briefingText,
          length: briefingText?.length || 0,
          preview: briefingText?.substring(0, 100),
        },
        statementOfFacts: {
          exists: !!statementOfFactsText,
          length: statementOfFactsText?.length || 0,
          preview: statementOfFactsText?.substring(0, 100),
        },
        studyGuide: {
          exists: !!studyGuideText,
          length: studyGuideText?.length || 0,
          preview: studyGuideText?.substring(0, 100),
        },
        report: {
          exists: !!reportText,
          length: reportText?.length || 0,
          preview: reportText?.substring(0, 100),
        },
        quiz: {
          exists: !!quizData,
          questionsCount: quizData?.questions?.length || 0,
        },
        flashcards: {
          exists: !!flashcards,
          counts: flashcards?.counts || {},
          totalCards: flashcards ? (flashcards.easy?.length || 0) + (flashcards.medium?.length || 0) + (flashcards.full?.length || 0) : 0,
        },
        slides: {
          presented: {
            count: slidesPresentedFiles.length,
            files: slidesPresentedFiles.slice(0, 3),
          },
          detailed: {
            count: slidesDetailedFiles.length,
            files: slidesDetailedFiles.slice(0, 3),
          },
          facts: {
            count: slidesFactsFiles.length,
            files: slidesFactsFiles.slice(0, 3),
          },
        },
        infographics: {
          concise: infConcise,
          standard: infStandard,
          bentoGrid: infBento,
        },
        mindmap: {
          exists: hasMindmap,
        },
        assets: {
          videoUrl: assetUrls.videoUrl,
          audioUrl: assetUrls.audioUrl,
          mindmapUrl: assetUrls.mindmapUrl,
        },
      },
    };

    console.log("Diagnostics:", JSON.stringify(diagnostics, null, 2));

    return NextResponse.json(diagnostics);
  } catch (error) {
    console.error("Debug endpoint error:", error);
    return NextResponse.json(
      { error: String(error) },
      { status: 500 }
    );
  }
}

// DEV ONLY — seeds test purchase/subscription records directly in DB
import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/db";

export async function POST(request: NextRequest) {
  if (process.env.NODE_ENV !== "development") {
    return NextResponse.json({ error: "Not available in production" }, { status: 403 });
  }

  const user = await getCurrentUser();
  if (!user) return NextResponse.json({ error: "Not logged in" }, { status: 401 });

  const { type } = await request.json() as { type: "lifetime" | "monthly" };

  if (type === "lifetime") {
    await prisma.purchase.upsert({
      where: { stripePaymentIntentId: `dev_lifetime_${user.id}` },
      create: {
        id: crypto.randomUUID(),
        updatedAt: new Date(),
        userId: user.id,
        planId: "complete",
        planName: "Complete Seerah (dev test)",
        amount: 4900,
        currency: "usd",
        stripePaymentIntentId: `dev_lifetime_${user.id}`,
        status: "succeeded",
      },
      update: { status: "succeeded" },
    });
    await prisma.user.update({ where: { id: user.id }, data: { hasPaid: true } });
    return NextResponse.json({ ok: true, granted: "lifetime" });
  }

  if (type === "monthly") {
    const now = new Date();
    const periodEnd = new Date(now.getTime() + 30 * 24 * 60 * 60 * 1000);
    await prisma.subscription.upsert({
      where: { stripeSubscriptionId: `dev_sub_${user.id}` },
      create: {
        id: crypto.randomUUID(),
        updatedAt: new Date(),
        userId: user.id,
        stripeCustomerId: `dev_cus_${user.id}`,
        stripeSubscriptionId: `dev_sub_${user.id}`,
        stripePriceId: process.env.STRIPE_MONTHLY_PRICE_ID ?? "dev_price",
        status: "active",
        currentPeriodStart: now,
        currentPeriodEnd: periodEnd,
        cancelAtPeriodEnd: false,
      },
      update: {
        status: "active",
        currentPeriodStart: now,
        currentPeriodEnd: periodEnd,
        cancelAtPeriodEnd: false,
        updatedAt: now,
      },
    });
    return NextResponse.json({ ok: true, granted: "monthly" });
  }

  return NextResponse.json({ error: "type must be lifetime or monthly" }, { status: 400 });
}

// Also allow DELETE to revoke test access
export async function DELETE(request: NextRequest) {
  if (process.env.NODE_ENV !== "development") {
    return NextResponse.json({ error: "Not available in production" }, { status: 403 });
  }

  const user = await getCurrentUser();
  if (!user) return NextResponse.json({ error: "Not logged in" }, { status: 401 });

  await prisma.purchase.deleteMany({ where: { stripePaymentIntentId: `dev_lifetime_${user.id}` } });
  await prisma.subscription.deleteMany({ where: { stripeSubscriptionId: `dev_sub_${user.id}` } });
  await prisma.user.update({ where: { id: user.id }, data: { hasPaid: false } });

  return NextResponse.json({ ok: true, revoked: true });
}

import { NextRequest, NextResponse } from "next/server";
import { r2StreamFile, r2GetMetadata, r2GetAudioKey, generateETag, isCached } from "@/lib/r2";
import { requirePartAccess } from "@/lib/part-access";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

export async function GET(
  req: NextRequest,
  { params }: { params: Promise<{ part: string }> }
) {
  // In production all audio is served via direct Cloudflare R2 public URLs.
  // This proxy route exists only for local development (no R2 configured).
  if (process.env.NODE_ENV === "production") {
    return new NextResponse(
      "Deprecated: use the direct R2 public URL returned by getPartAssetUrls()",
      { status: 410 }
    );
  }

  const { part } = await params;
  const partNum = parseInt(part, 10);
  if (isNaN(partNum)) return new NextResponse("Bad request", { status: 400 });

  const deny = await requirePartAccess(partNum);
  if (deny) return deny;

  try {
    const audioKey = await r2GetAudioKey(partNum);

    if (!audioKey) {
      return new NextResponse("Not found", { status: 404 });
    }

    const metadata = await r2GetMetadata(audioKey);

    if (!metadata) {
      return new NextResponse("Not found", { status: 404 });
    }

    const fileSize = metadata.size;
    const etag = generateETag({ size: metadata.size, lastModified: metadata.lastModified });
    const clientETag = req.headers.get("if-none-match");

    if (isCached(etag, clientETag)) {
      return new NextResponse(null, { status: 304 });
    }

    const rangeHeader = req.headers.get("range");

    if (!rangeHeader) {
      const response = await r2StreamFile(audioKey);

      if (!response.Body) {
        return new NextResponse("Error reading file", { status: 500 });
      }

      const stream = response.Body.transformToWebStream();

      return new NextResponse(stream as any, {
        status: 200,
        headers: {
          "Content-Type": "audio/mpeg",
          "Content-Length": String(fileSize),
          "Accept-Ranges": "bytes",
          "Cache-Control": "private, max-age=3600",
          "ETag": etag,
        },
      });
    }

    const match = /bytes=(\d+)-(\d*)/.exec(rangeHeader);

    if (!match) {
      return new NextResponse("Invalid range", { status: 416 });
    }

    const start = parseInt(match[1], 10);
    const end = match[2] ? parseInt(match[2], 10) : fileSize - 1;

    if (start >= fileSize || end >= fileSize || start > end) {
      return new NextResponse("Range Not Satisfiable", {
        status: 416,
        headers: { "Content-Range": `bytes */${fileSize}` },
      });
    }

    const chunkSize = end - start + 1;

    const response = await r2StreamFile(audioKey, `bytes=${start}-${end}`);

    if (!response.Body) {
      return new NextResponse("Error reading file", { status: 500 });
    }

    const stream = response.Body.transformToWebStream();

    return new NextResponse(stream as any, {
      status: 206,
      headers: {
        "Content-Range": `bytes ${start}-${end}/${fileSize}`,
        "Accept-Ranges": "bytes",
        "Content-Length": String(chunkSize),
        "Content-Type": "audio/mpeg",
        "Cache-Control": "private, max-age=3600",
        "ETag": etag,
      },
    });
  } catch (error) {
    console.error("Error streaming audio from R2:", error);
    return new NextResponse("Internal server error", { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { r2StreamFile, r2GetMetadata, generateETag, isCached } from "@/lib/r2";
import { requirePartAccess, extractPartNumberFromR2Key } from "@/lib/part-access";
import { getCurrentUser } from "@/lib/auth";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

const MIME: Record<string, string> = {
  ".png": "image/png",
  ".jpg": "image/jpeg",
  ".jpeg": "image/jpeg",
  ".webp": "image/webp",
  ".gif": "image/gif",
};

function getMimeType(key: string): string {
  const ext = key.substring(key.lastIndexOf(".")).toLowerCase();
  return MIME[ext] ?? "application/octet-stream";
}

export async function GET(req: NextRequest) {
  const { searchParams } = req.nextUrl;
  const relPath = searchParams.get("p");

  if (!relPath) return new NextResponse("Missing path", { status: 400 });

  try {
    const key = relPath.startsWith("/") ? relPath.slice(1) : relPath;

    // Access control: if the key contains a part number, enforce per-part access rules.
    // Keys without a part number (thumbnails, etc.) still require a valid session.
    const partNumber = extractPartNumberFromR2Key(key);
    if (partNumber !== null) {
      const deny = await requirePartAccess(partNumber);
      if (deny) return deny;
    } else {
      const user = await getCurrentUser();
      if (!user) return new NextResponse("Authentication required", { status: 401 });
    }

    // Get file metadata
    const metadata = await r2GetMetadata(key);
    
    if (!metadata) {
      return new NextResponse("Not found", { status: 404 });
    }

    // Generate ETag and check cache
    const etag = generateETag({ size: metadata.size, lastModified: metadata.lastModified });
    const clientETag = req.headers.get("if-none-match");
    
    if (isCached(etag, clientETag)) {
      return new NextResponse(null, { status: 304 });
    }

    // Determine content type
    const contentType = getMimeType(key);

    // Stream file from R2
    const response = await r2StreamFile(key);
    
    if (!response.Body) {
      return new NextResponse("Error reading file", { status: 500 });
    }

    const stream = response.Body.transformToWebStream();

    return new NextResponse(stream as any, {
      status: 200,
      headers: {
        "Content-Type": contentType,
        "Content-Length": String(metadata.size),
        "Cache-Control": "public, max-age=31536000, immutable",
        "ETag": etag,
      },
    });
  } catch (error) {
    console.error("Error streaming image from R2:", error);
    return new NextResponse("Internal server error", { status: 500 });
  }
}

