import { notFound, redirect } from "next/navigation";
import Link from "next/link";
import { requireStudent } from "@/lib/auth";
import { getStudentLessonData } from "@/lib/queries/student";
import { getPartById } from "@/lib/content";
import { ERA_MAP } from "@/lib/types";
import {
  readBriefing,
  readStatementOfFacts,
  readStudyGuide,
  readReport,
  getSlideFiles,
  getInfographicFilename,
  mindmapExists,
  readQuiz,
  readFlashcards,
  getPartAssetUrls,
} from "@/lib/files";
import { getR2AssetUrl, generateSignedR2Url, IMAGE_URL_EXPIRY } from "@/lib/r2";
import {
  ArrowLeft,
  ChevronLeft,
  ChevronRight,
  Clock,
  BookOpen,
  Lock,
  Brain,
} from "lucide-react";
import { PartTabs } from "@/components/part/part-tabs";
import { MarkCompleteButton } from "./mark-complete-button";

export const dynamic = "force-dynamic";

interface Props {
  params: Promise<{ classId: string; partNumber: string }>;
}

export async function generateMetadata({ params }: Props) {
  const { partNumber } = await params;
  const num = parseInt(partNumber, 10);
  const part = getPartById(`part-${num}`);
  return { title: part ? `Part ${num}: ${part.title}` : "Lesson" };
}

export default async function StudentLessonPage({ params }: Props) {
  const user = await requireStudent();
  if (!user.studentProfileId) notFound();

  const { classId, partNumber: partNumberStr } = await params;
  const partNum = parseInt(partNumberStr, 10);
  if (isNaN(partNum)) notFound();

  const data = await getStudentLessonData(user.studentProfileId, classId, partNum);
  if (!data) notFound();

  if (data.locked) {
    // Server-side gate: lesson not released, redirect back to class view
    redirect(`/student/classes/${classId}`);
  }

  const { item, cls, progress, quiz, quizAttempts, prevItem, nextItem } = data;
  const partBase = getPartById(`part-${partNum}`);
  if (!partBase) notFound();

  const n = partBase.partNumber;

  // Class-based lessons: students get full access since teacher controls pacing
  const userPlan = "complete" as const;

  // Load assets from R2
  const [
    briefingText,
    statementOfFactsText,
    studyGuideText,
    reportText,
    quizData,
    flashcards,
    slidesPresentedFiles,
    slidesDetailedFiles,
    slidesFactsFiles,
    infConcise,
    infStandard,
    infBento,
    hasMindmap,
    assetUrls,
  ] = await Promise.all([
    readBriefing(n),
    readStatementOfFacts(n),
    readStudyGuide(n),
    readReport(n),
    readQuiz(n),
    readFlashcards(n),
    getSlideFiles(n, "presented"),
    getSlideFiles(n, "detailed"),
    getSlideFiles(n, "facts"),
    getInfographicFilename(n, "Concise"),
    getInfographicFilename(n, "Standard"),
    getInfographicFilename(n, "Bento Grid"),
    mindmapExists(n),
    getPartAssetUrls(n),
  ]);

  const slideFiles = {
    presented: slidesPresentedFiles,
    detailed: slidesDetailedFiles,
    facts: slidesFactsFiles,
  };

  const part = {
    ...partBase,
    assets: {
      ...partBase.assets,
      videoUrl: assetUrls.videoUrl ?? undefined,
      audioUrl: assetUrls.audioUrl ?? undefined,
      briefingText: briefingText ?? undefined,
      statementOfFactsText: statementOfFactsText ?? undefined,
      studyGuideText: studyGuideText ?? undefined,
      reportText: reportText ?? undefined,
      mindmapUrl: assetUrls.mindmapUrl ?? undefined,
      quiz: quizData ?? undefined,
      flashcards: flashcards ?? undefined,
      slides: slideFiles,
      infographics: await (async () => {
        const sign = (key: string | null, localFolder: string) =>
          key
            ? key.includes("/")
              ? generateSignedR2Url(key, IMAGE_URL_EXPIRY)
              : Promise.resolve(`/seerah-media/Infographics/${localFolder}/${key}`)
            : Promise.resolve(undefined);

        const [concise, standard, bentoGrid] = await Promise.all([
          sign(infConcise, "Concise"),
          sign(infStandard, "Standard"),
          sign(infBento, "Bento Grid"),
        ]);
        return { concise, standard, bentoGrid };
      })(),
    },
  };

  const era = ERA_MAP[part.era];
  const isCompleted = progress?.status === "completed";
  const bestScore = quizAttempts.length > 0
    ? Math.max(...quizAttempts.map((a) => a.score ?? 0))
    : null;

  return (
    <div className="min-h-full">
      {/* ── Top bar: back to class + mark complete ─────────────────── */}
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 pt-5 sm:pt-6">
        <div className="flex items-center justify-between gap-4 flex-wrap">
          <Link
            href={`/student/classes/${classId}`}
            className="inline-flex items-center gap-1.5 text-text-muted hover:text-text text-sm transition-colors"
          >
            <ArrowLeft className="w-4 h-4" />
            {cls.title}
          </Link>
          <MarkCompleteButton
            classId={classId}
            classCourseItemId={item.id}
            isCompleted={isCompleted}
          />
        </div>
      </div>

      {/* ── Hero ─────────────────────────────────────────────────────── */}
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 mt-5 mb-6">
        <div className="rounded-2xl bg-surface border border-border/70 overflow-hidden">
          <div className="h-px w-full bg-gradient-to-r from-transparent via-gold/35 to-transparent" />
          <div className="p-6 sm:p-8">
            <div className="flex flex-wrap items-center gap-2 mb-5">
              <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-gold/12 border border-gold/25 text-gold text-xs font-semibold">
                Part {part.partNumber}
              </span>
              {era && (
                <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-surface-raised border border-border text-text-secondary text-xs font-medium">
                  <span
                    className="w-1.5 h-1.5 rounded-full flex-shrink-0"
                    style={{ backgroundColor: era.color }}
                  />
                  {era.label}
                </span>
              )}
              {part.duration && (
                <span className="inline-flex items-center gap-1.5 text-xs text-text-muted">
                  <Clock className="w-3 h-3" />
                  {part.duration}
                </span>
              )}
              {item.moduleName && (
                <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-surface-raised border border-border text-text-muted text-xs">
                  {item.moduleName}
                </span>
              )}
            </div>

            <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-text leading-tight tracking-tight">
              {part.title}
            </h1>
            {part.subtitle && (
              <p className="mt-2 text-base sm:text-lg text-text-secondary leading-snug">{part.subtitle}</p>
            )}

            <div className="mt-6 flex gap-4 p-4 sm:p-5 rounded-xl bg-surface-raised border border-border/60">
              <div className="flex-shrink-0 mt-0.5">
                <div className="w-7 h-7 rounded-lg bg-gold/10 border border-gold/20 flex items-center justify-center">
                  <BookOpen className="w-3.5 h-3.5 text-gold/70" />
                </div>
              </div>
              <div>
                <p className="text-[11px] font-semibold uppercase tracking-widest text-gold/60 mb-1.5">
                  About this lesson
                </p>
                <p className="text-sm text-text-secondary leading-relaxed">{part.description}</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ── Content tabs ─────────────────────────────────────────────── */}
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <PartTabs part={part} userPlan={userPlan} />
      </div>

      {/* ── Quiz section ─────────────────────────────────────────────── */}
      {(quiz || bestScore !== null) && (
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 mt-10">
          <div className="p-5 rounded-2xl border border-border bg-surface">
            <div className="flex items-center justify-between gap-4 flex-wrap">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-gold/10 border border-gold/20 flex items-center justify-center">
                  <Brain className="w-5 h-5 text-gold" />
                </div>
                <div>
                  <p className="font-semibold text-text text-sm">
                    {quiz?.title ?? "Part Quiz"}
                  </p>
                  {bestScore !== null && (
                    <p className={`text-xs ${bestScore >= (quiz?.passingScore ?? 70) ? "text-success" : "text-error"}`}>
                      Best score: {bestScore}%
                    </p>
                  )}
                  {!quiz && (
                    <p className="text-xs text-text-muted flex items-center gap-1">
                      <Lock className="w-3 h-3" /> Not yet unlocked by teacher
                    </p>
                  )}
                </div>
              </div>
              {quiz && (
                <Link
                  href={`/student/classes/${classId}/quiz/${quiz.id}`}
                  className="px-4 py-2 rounded-xl bg-gold/10 border border-gold/30 text-gold text-sm font-medium hover:bg-gold/20 transition-colors"
                >
                  {quizAttempts.length > 0 ? "Retake quiz" : "Start quiz"}
                </Link>
              )}
            </div>
          </div>
        </div>
      )}

      {/* ── Prev / Next navigation within class ──────────────────────── */}
      {(prevItem || nextItem) && (
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 mt-10 pb-12">
          <div className="flex items-center gap-3 mb-5">
            <div className="h-px flex-1 bg-border/60" />
            <span className="text-[10px] font-semibold tracking-[0.2em] uppercase text-text-muted">
              Continue the journey
            </span>
            <div className="h-px flex-1 bg-border/60" />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <div>
              {prevItem ? (
                <Link
                  href={`/student/classes/${classId}/lesson/${prevItem.seerahPart.partNumber}`}
                  className="group flex flex-col gap-2.5 p-5 rounded-xl border border-border bg-surface hover:bg-surface-raised transition-all h-full"
                >
                  <div className="flex items-center gap-1.5 text-[11px] text-text-muted group-hover:text-text-secondary transition-colors">
                    <ChevronLeft className="w-3 h-3" />
                    Previous lesson
                  </div>
                  <p className="text-sm font-semibold text-text line-clamp-2">
                    {prevItem.seerahPart.title}
                  </p>
                </Link>
              ) : (
                <div />
              )}
            </div>
            <div>
              {nextItem ? (
                <Link
                  href={`/student/classes/${classId}/lesson/${nextItem.seerahPart.partNumber}`}
                  className="group relative flex flex-col gap-2.5 p-5 rounded-xl border border-gold/25 bg-gradient-to-br from-gold/8 to-gold/4 hover:border-gold/40 transition-all h-full overflow-hidden"
                >
                  <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-gold/30 to-transparent" />
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-semibold uppercase tracking-widest text-gold/60">
                      Up next
                    </span>
                    <ChevronRight className="w-3.5 h-3.5 text-gold/50 group-hover:text-gold transition-all" />
                  </div>
                  <p className="text-sm font-semibold text-text line-clamp-2">
                    {nextItem.seerahPart.title}
                  </p>
                </Link>
              ) : (
                <div />
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { redirect } from "next/navigation";
import Link from "next/link";
import { requireStudent } from "@/lib/auth";
import { getProfilesWithProgress } from "@/app/actions/profiles";
import { isFamilyPlan, getProfileLimit } from "@/lib/access";
import { StudentLayout } from "@/components/student/student-layout";
import { ProfilesClient } from "./profiles-client";

export const metadata = { title: "Learner Profiles | Complete Seerah" };
export const dynamic = "force-dynamic";

export default async function ProfilesPage() {
  const user = await requireStudent();
  if (!user.studentProfileId) redirect("/");

  const profiles = await getProfilesWithProgress();
  const isFamily = isFamilyPlan(user.planType);
  const profileLimit = getProfileLimit(user.planType);

  return (
    <StudentLayout
      userPlan="complete"
      userName={user.fullName}
      activeProfileName={user.activeProfileName}
      planType={user.planType}
    >
      <ProfilesClient
        profiles={profiles}
        isFamily={isFamily}
        profileLimit={profileLimit}
        currentUserId={user.id}
        activeProfileId={user.activeProfileId}
      />
    </StudentLayout>
  );
}

"use client";

import { useState, useTransition } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import {
  Plus, Edit2, Trash2, ArrowLeft,
  Video, BookOpen, Brain, ClipboardCheck,
  Image, Map, FileText, Layers, BarChart2,
  ChevronRight, Check,
} from "lucide-react";
import {
  createProfile,
  updateProfile,
  deleteProfile,
  setDefaultProfile,
  switchProfile,
} from "@/app/actions/profiles";

// ─── Types ────────────────────────────────────────────────────

interface ProfileStats {
  completedParts: number;
  totalParts: number;
  completionPercent: number;
  videosCompleted: number;
  briefingsOpened: number;
  slidesViewed: number;
  infographicsViewed: number;
  mindmapsViewed: number;
  audioCompleted: number;
  flashcardsStudied: number;
  quizzesPassed: number;
  factsViewed: number;
  lastActivity: Date | null;
}

interface ProfileData {
  id: string;
  displayName: string;
  avatar: string | null;
  isDefault: boolean;
  createdAt: Date;
  stats: ProfileStats;
}

interface ProfilesClientProps {
  profiles: ProfileData[];
  isFamily: boolean;
  profileLimit: number;
  currentUserId: string;
  activeProfileId: string | null;
}

// Avatar options
const AVATARS = [
  "🌙", "⭐", "📖", "🌿", "🕌", "🦋",
  "🌸", "🏅", "🌺", "🎯", "📚", "✨",
  "🦁", "🐬", "🦅", "🌊", "🏔️", "🌍",
];

// Distinct tile background colors per slot (Netflix-style)
const TILE_COLORS = [
  "from-amber-900/80 to-amber-800/40",
  "from-violet-900/80 to-violet-800/40",
  "from-teal-900/80 to-teal-800/40",
  "from-rose-900/80 to-rose-800/40",
  "from-sky-900/80 to-sky-800/40",
];

// ─── Main component ───────────────────────────────────────────

export function ProfilesClient({
  profiles,
  isFamily,
  profileLimit,
  activeProfileId,
}: ProfilesClientProps) {
  const router = useRouter();
  const [isPending, startTransition] = useTransition();
  const [selectedProfile, setSelectedProfile] = useState<ProfileData | null>(null);
  const [mode, setMode] = useState<"list" | "new" | "edit" | "detail">("list");
  const [formName, setFormName] = useState("");
  const [formAvatar, setFormAvatar] = useState<string | null>(null);
  const [formError, setFormError] = useState<string | null>(null);
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);
  const [actionMessage, setActionMessage] = useState<string | null>(null);
  const [switchingId, setSwitchingId] = useState<string | null>(null);

  const canAddMore = profiles.length < profileLimit;

  function showMessage(msg: string) {
    setActionMessage(msg);
    setTimeout(() => setActionMessage(null), 3000);
  }

  function openNewForm() {
    setFormName("");
    setFormAvatar(null);
    setFormError(null);
    setMode("new");
  }

  function openEditForm(profile: ProfileData) {
    setSelectedProfile(profile);
    setFormName(profile.displayName);
    setFormAvatar(profile.avatar);
    setFormError(null);
    setMode("edit");
  }

  function openDetail(profile: ProfileData) {
    setSelectedProfile(profile);
    setMode("detail");
  }

  async function handleCreate() {
    if (!formName.trim()) { setFormError("Please enter a name."); return; }
    startTransition(async () => {
      const result = await createProfile(formName.trim(), formAvatar ?? undefined);
      if (result.success) { setMode("list"); showMessage("Profile created."); router.refresh(); }
      else setFormError(result.error ?? "Failed to create profile.");
    });
  }

  async function handleUpdate() {
    if (!selectedProfile) return;
    if (!formName.trim()) { setFormError("Please enter a name."); return; }
    startTransition(async () => {
      const result = await updateProfile(selectedProfile.id, { displayName: formName.trim(), avatar: formAvatar });
      if (result.success) { setMode("list"); showMessage("Profile updated."); router.refresh(); }
      else setFormError(result.error ?? "Failed to update profile.");
    });
  }

  async function handleDelete(profileId: string) {
    startTransition(async () => {
      const result = await deleteProfile(profileId);
      if (result.success) { setConfirmDelete(null); setMode("list"); showMessage("Profile deleted."); router.refresh(); }
      else showMessage(result.error ?? "Failed to delete profile.");
    });
  }

  async function handleSwitch(profileId: string) {
    setSwitchingId(profileId);
    startTransition(async () => {
      await switchProfile(profileId);
      router.push("/seerah");
    });
  }

  // ── Detail view ────────────────────────────────────────────────────────────

  if (mode === "detail" && selectedProfile) {
    const s = selectedProfile.stats;
    return (
      <div className="min-h-screen bg-zinc-950 px-4 py-8 max-w-2xl mx-auto">
        <button onClick={() => setMode("list")} className="flex items-center gap-2 text-zinc-400 hover:text-white mb-6 transition-colors text-sm">
          <ArrowLeft className="w-4 h-4" />Back to profiles
        </button>

        <div className="flex items-center gap-4 mb-8">
          <div className={`w-16 h-16 rounded-xl bg-gradient-to-br ${TILE_COLORS[profiles.findIndex(p => p.id === selectedProfile.id) % TILE_COLORS.length]} flex items-center justify-center text-3xl border border-white/10`}>
            {selectedProfile.avatar ?? (
              <span className="text-xl font-bold text-white/80">
                {selectedProfile.displayName.slice(0, 2).toUpperCase()}
              </span>
            )}
          </div>
          <div>
            <h1 className="text-xl font-bold text-white">{selectedProfile.displayName}</h1>
            <p className="text-xs text-zinc-500 mt-0.5">{selectedProfile.isDefault ? "Primary profile" : "Learner profile"}</p>
          </div>
        </div>

        <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5 mb-4">
          <h2 className="text-xs font-semibold text-zinc-500 mb-3 uppercase tracking-wider">Overall Progress</h2>
          <div className="flex items-end gap-3 mb-3">
            <span className="text-4xl font-bold text-amber-400">{s.completionPercent}%</span>
            <span className="text-zinc-500 text-sm pb-1">{s.completedParts}/{s.totalParts} lessons</span>
          </div>
          <div className="w-full h-2 bg-zinc-800 rounded-full overflow-hidden">
            <div className="h-full bg-amber-500 rounded-full transition-all" style={{ width: `${s.completionPercent}%` }} />
          </div>
          {s.lastActivity && (
            <p className="text-xs text-zinc-600 mt-3">Last active: {new Date(s.lastActivity).toLocaleDateString()}</p>
          )}
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
          {[
            { label: "Videos",       value: s.videosCompleted,    icon: Video,          color: "text-blue-400" },
            { label: "Briefings",    value: s.briefingsOpened,    icon: BookOpen,       color: "text-green-400" },
            { label: "Slides",       value: s.slidesViewed,       icon: Layers,         color: "text-purple-400" },
            { label: "Infographics", value: s.infographicsViewed, icon: Image,          color: "text-pink-400" },
            { label: "Mind Maps",    value: s.mindmapsViewed,     icon: Map,            color: "text-teal-400" },
            { label: "Audio",        value: s.audioCompleted,     icon: FileText,       color: "text-orange-400" },
            { label: "Flashcards",   value: s.flashcardsStudied,  icon: Brain,          color: "text-amber-400" },
            { label: "Quizzes",      value: s.quizzesPassed,      icon: ClipboardCheck, color: "text-red-400" },
            { label: "Facts",        value: s.factsViewed,        icon: FileText,       color: "text-indigo-400" },
          ].map(({ label, value, icon: Icon, color }) => (
            <div key={label} className="bg-zinc-900 rounded-xl border border-zinc-800 p-4 flex items-center gap-3">
              <div className="w-8 h-8 rounded-lg bg-zinc-800 flex items-center justify-center flex-shrink-0">
                <Icon className={`w-4 h-4 ${color}`} />
              </div>
              <div>
                <p className="text-xs text-zinc-500">{label}</p>
                <p className="text-sm font-bold text-white">{value}<span className="text-zinc-600 font-normal text-xs"> / 100</span></p>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-6 flex gap-3">
          <button onClick={() => openEditForm(selectedProfile)} className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg bg-zinc-800 hover:bg-zinc-700 text-white text-sm font-medium transition-colors">
            <Edit2 className="w-4 h-4" />Edit Profile
          </button>
          <button onClick={() => handleSwitch(selectedProfile.id)} disabled={isPending} className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg bg-amber-500 hover:bg-amber-400 text-black text-sm font-bold transition-colors disabled:opacity-50">
            Learn as {selectedProfile.displayName}
          </button>
        </div>
      </div>
    );
  }

  // ── Form (new / edit) ──────────────────────────────────────────────────────

  if (mode === "new" || mode === "edit") {
    const isEdit = mode === "edit";
    return (
      <div className="min-h-screen bg-zinc-950 px-4 py-8 max-w-lg mx-auto">
        <button onClick={() => setMode("list")} className="flex items-center gap-2 text-zinc-400 hover:text-white mb-6 transition-colors text-sm">
          <ArrowLeft className="w-4 h-4" />Back
        </button>

        <h1 className="text-xl font-bold text-white mb-6">
          {isEdit ? "Edit Profile" : "Create New Profile"}
        </h1>

        <div className="mb-5">
          <label className="block text-sm font-medium text-zinc-300 mb-1.5">
            Name <span className="text-red-400">*</span>
          </label>
          <input
            type="text"
            value={formName}
            onChange={(e) => setFormName(e.target.value)}
            placeholder="e.g. Ahmad, Maryam, Dad…"
            maxLength={50}
            className="w-full px-4 py-2.5 bg-zinc-900 border border-zinc-700 focus:border-amber-500 rounded-lg text-white placeholder:text-zinc-600 outline-none transition-colors"
          />
        </div>

        <div className="mb-5">
          <label className="block text-sm font-medium text-zinc-300 mb-1.5">Avatar (optional)</label>
          <div className="grid grid-cols-9 gap-2">
            {AVATARS.map((emoji) => (
              <button
                key={emoji}
                type="button"
                onClick={() => setFormAvatar(formAvatar === emoji ? null : emoji)}
                className={`w-9 h-9 rounded-lg text-lg flex items-center justify-center transition-all ${
                  formAvatar === emoji
                    ? "bg-amber-500/20 border-2 border-amber-500"
                    : "bg-zinc-800 border border-zinc-700 hover:border-amber-500/50"
                }`}
              >
                {emoji}
              </button>
            ))}
          </div>
          {formAvatar && (
            <button type="button" onClick={() => setFormAvatar(null)} className="mt-2 text-xs text-zinc-500 hover:text-zinc-300 transition-colors">
              Clear avatar
            </button>
          )}
        </div>

        {formError && (
          <p className="mb-4 text-sm text-red-400 bg-red-500/10 border border-red-500/20 rounded-lg px-4 py-2.5">{formError}</p>
        )}

        <div className="flex gap-3">
          <button type="button" onClick={() => setMode("list")} className="flex-1 px-4 py-2.5 rounded-lg border border-zinc-700 text-zinc-300 hover:text-white hover:border-zinc-500 text-sm font-medium transition-colors">
            Cancel
          </button>
          <button type="button" onClick={isEdit ? handleUpdate : handleCreate} disabled={isPending || !formName.trim()} className="flex-1 px-4 py-2.5 rounded-lg bg-amber-500 hover:bg-amber-400 text-black font-bold text-sm transition-colors disabled:opacity-50">
            {isPending ? "Saving…" : isEdit ? "Save Changes" : "Create Profile"}
          </button>
        </div>

        {isEdit && selectedProfile && !selectedProfile.isDefault && profiles.length > 1 && (
          <div className="mt-8 pt-6 border-t border-zinc-800">
            {confirmDelete === selectedProfile.id ? (
              <div className="bg-red-500/10 border border-red-500/20 rounded-lg p-4">
                <p className="text-sm text-red-400 mb-3">
                  Delete &ldquo;{selectedProfile.displayName}&rdquo;? Their progress data will be permanently removed.
                </p>
                <div className="flex gap-3">
                  <button onClick={() => setConfirmDelete(null)} className="flex-1 px-3 py-2 rounded-lg border border-zinc-700 text-zinc-400 text-sm hover:text-white transition-colors">Cancel</button>
                  <button onClick={() => handleDelete(selectedProfile.id)} disabled={isPending} className="flex-1 px-3 py-2 rounded-lg bg-red-600 hover:bg-red-500 text-white text-sm font-medium transition-colors disabled:opacity-50">
                    {isPending ? "Deleting…" : "Delete Profile"}
                  </button>
                </div>
              </div>
            ) : (
              <button onClick={() => setConfirmDelete(selectedProfile.id)} className="flex items-center gap-2 text-sm text-red-400/70 hover:text-red-400 transition-colors">
                <Trash2 className="w-4 h-4" />Delete this profile
              </button>
            )}
          </div>
        )}
      </div>
    );
  }

  // ── Netflix-style profile grid ─────────────────────────────────────────────

  return (
    <div className="min-h-screen bg-zinc-950 flex flex-col items-center justify-start px-4 py-12">

      {/* Header */}
      <div className="text-center mb-10">
        <h1 className="text-3xl font-bold text-white tracking-tight">Who&apos;s learning?</h1>
        {isFamily && (
          <p className="text-zinc-500 text-sm mt-2">Family Access · up to {profileLimit} learner profiles</p>
        )}
      </div>

      {/* Action message */}
      {actionMessage && (
        <div className="mb-6 px-4 py-2.5 bg-green-500/10 border border-green-500/20 rounded-lg text-sm text-green-400">
          {actionMessage}
        </div>
      )}

      {/* Profile tiles */}
      <div className="flex flex-wrap justify-center gap-6 max-w-3xl">
        {profiles.map((profile, idx) => {
          const isActive = profile.id === activeProfileId;
          const isSwitching = switchingId === profile.id && isPending;
          const initials = profile.displayName.split(" ").map((w) => w[0]).join("").slice(0, 2).toUpperCase();
          const tileGradient = TILE_COLORS[idx % TILE_COLORS.length];

          return (
            <div key={profile.id} className="flex flex-col items-center gap-3 group">
              {/* Square tile */}
              <div className="relative">
                <button
                  onClick={() => handleSwitch(profile.id)}
                  disabled={isPending}
                  className={`
                    w-32 h-32 rounded-xl bg-gradient-to-br ${tileGradient}
                    flex items-center justify-center text-5xl
                    border-2 transition-all duration-200
                    ${isActive
                      ? "border-amber-400 shadow-lg shadow-amber-500/30 scale-105"
                      : "border-transparent hover:border-white/30 hover:scale-105 hover:brightness-125"
                    }
                    disabled:cursor-wait
                  `}
                  title={`Learn as ${profile.displayName}`}
                >
                  {isSwitching ? (
                    <div className="w-7 h-7 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  ) : profile.avatar ? (
                    profile.avatar
                  ) : (
                    <span className="text-2xl font-bold text-white/80">{initials}</span>
                  )}

                  {/* Active checkmark badge */}
                  {isActive && !isSwitching && (
                    <div className="absolute -top-2 -right-2 w-6 h-6 rounded-full bg-amber-400 flex items-center justify-center shadow-md">
                      <Check className="w-3.5 h-3.5 text-black" strokeWidth={3} />
                    </div>
                  )}
                </button>

                {/* Hover action bar — edit + stats */}
                <div className="absolute inset-x-0 -bottom-1 flex items-center justify-center gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity duration-150">
                  <button
                    onClick={(e) => { e.stopPropagation(); openEditForm(profile); }}
                    className="w-7 h-7 rounded-full bg-zinc-900 border border-zinc-700 hover:border-zinc-500 flex items-center justify-center text-zinc-400 hover:text-white transition-colors shadow-md"
                    title="Edit profile"
                  >
                    <Edit2 className="w-3 h-3" />
                  </button>
                  <button
                    onClick={(e) => { e.stopPropagation(); openDetail(profile); }}
                    className="w-7 h-7 rounded-full bg-zinc-900 border border-zinc-700 hover:border-zinc-500 flex items-center justify-center text-zinc-400 hover:text-white transition-colors shadow-md"
                    title="View progress"
                  >
                    <BarChart2 className="w-3 h-3" />
                  </button>
                </div>
              </div>

              {/* Name + progress */}
              <div className="text-center">
                <p className={`text-sm font-semibold transition-colors ${isActive ? "text-amber-400" : "text-zinc-200 group-hover:text-white"}`}>
                  {profile.displayName}
                </p>
                <div className="flex items-center gap-1.5 mt-1 justify-center">
                  {/* Mini progress dots or bar */}
                  <div className="w-16 h-1 bg-zinc-800 rounded-full overflow-hidden">
                    <div className="h-full bg-amber-500 rounded-full" style={{ width: `${profile.stats.completionPercent}%` }} />
                  </div>
                  <span className="text-[10px] text-zinc-600">{profile.stats.completionPercent}%</span>
                </div>
                {isActive && (
                  <span className="inline-block mt-1 text-[10px] font-semibold text-amber-500 uppercase tracking-wider">
                    Active
                  </span>
                )}
                {profile.isDefault && !isActive && (
                  <span className="inline-block mt-1 text-[10px] text-zinc-600 uppercase tracking-wider">
                    Primary
                  </span>
                )}
              </div>
            </div>
          );
        })}

        {/* Add profile tile */}
        {canAddMore && isFamily && (
          <div className="flex flex-col items-center gap-3 group">
            <button
              onClick={openNewForm}
              className="w-32 h-32 rounded-xl border-2 border-dashed border-zinc-700 hover:border-amber-500/50 flex items-center justify-center transition-all duration-200 hover:scale-105 hover:bg-zinc-900/60"
            >
              <Plus className="w-8 h-8 text-zinc-600 group-hover:text-amber-500 transition-colors" />
            </button>
            <p className="text-sm text-zinc-600 group-hover:text-zinc-400 transition-colors">Add Profile</p>
          </div>
        )}
      </div>

      {/* Manage link */}
      <div className="mt-12 flex flex-col items-center gap-3">
        {isFamily && (
          <p className="text-xs text-zinc-600">Click a profile to start learning · hover to edit or view progress</p>
        )}
        {!isFamily && (
          <div className="mt-4 p-4 bg-amber-500/5 border border-amber-500/15 rounded-xl max-w-sm text-center">
            <p className="text-sm font-semibold text-amber-400 mb-1">Want profiles for the whole family?</p>
            <p className="text-xs text-zinc-500 mb-3">Family Access gives up to 5 separate learner profiles with independent progress tracking.</p>
            <Link href="/pricing" className="inline-flex items-center gap-1.5 px-4 py-2 rounded-lg bg-amber-500 hover:bg-amber-400 text-black text-sm font-bold transition-colors">
              Upgrade to Family Access <ChevronRight className="w-3.5 h-3.5" />
            </Link>
          </div>
        )}
      </div>
    </div>
  );
}

import { redirect } from "next/navigation";
import { requireStudent } from "@/lib/auth";
import { StudentLayout } from "@/components/student/student-layout";
import { prisma } from "@/lib/db";
import { getActiveProfileId } from "@/app/actions/profiles";
import { PARTS } from "@/lib/content";
import { TrendingUp, Target, Clock, Award, BookOpen, FileText, Headphones, Brain, ChevronRight } from "lucide-react";
import { FadeUp, StaggerChildren, AnimatedCard } from "@/components/motion";
import Link from "next/link";

export const metadata = { title: "Progress | Complete Seerah" };
export const dynamic = "force-dynamic";

function formatStudyTime(totalSeconds: number): string {
  if (totalSeconds < 60) return `${totalSeconds}s`;
  const minutes = Math.floor(totalSeconds / 60);
  if (minutes < 60) return `${minutes}m`;
  const hours = Math.floor(minutes / 60);
  const remainingMins = minutes % 60;
  return remainingMins > 0 ? `${hours}h ${remainingMins}m` : `${hours}h`;
}

export default async function ProgressPage() {
  const user = await requireStudent();
  if (!user.studentProfileId) redirect("/");

  if (!user.hasPaid) {
    const purchases = await prisma.purchase.findMany({
      where: { userId: user.id, status: "succeeded" },
    });
    if (purchases.length === 0) redirect("/pricing");
  }

  const userPlan = "complete" as const;

  // Resolve the active learner profile
  const learnerProfileId = user.activeProfileId ?? await getActiveProfileId(user.id);
  const profileName = user.activeProfileName ?? user.fullName.split(" ")[0];

  // Fetch all progress for this profile in parallel with study sessions
  const [allProgress, studySessions] = await Promise.all([
    prisma.partProgress.findMany({
      where: { learnerProfileId },
      orderBy: { partNumber: "asc" },
      select: {
        partNumber: true,
        status: true,
        videoWatchPercent: true,
        videoCompleted: true,
        briefingOpened: true,
        quizCompleted: true,
        quizPassed: true,
        quizBestScore: true,
        quizAttempts: true,
        flashcardsReviewed: true,
        openedAssets: true,
        startedAt: true,
        completedAt: true,
        lastAccessedAt: true,
      },
    }),
    prisma.studySession.findMany({
      where: { learnerProfileId },
      select: { secondsTracked: true, partNumber: true, startedAt: true },
    }),
  ]);

  const TOTAL_PARTS = 100;

  // Compute stats
  const completedParts = allProgress.filter(
    (p) => p.status === "completed" || p.status === "mastered"
  );
  const inProgressParts = allProgress.filter(
    (p) => p.status === "started" && (p.videoWatchPercent ?? 0) > 0
  );
  const completedCount = completedParts.length;
  const progressPercent = Math.round((completedCount / TOTAL_PARTS) * 100);

  const totalStudySeconds = studySessions.reduce((sum, s) => sum + s.secondsTracked, 0);

  const quizAttemptedRows = allProgress.filter((p) => (p.quizAttempts ?? 0) > 0 && p.quizBestScore != null);
  const avgQuizScore =
    quizAttemptedRows.length > 0
      ? Math.round(
          quizAttemptedRows.reduce((s, p) => s + (p.quizBestScore ?? 0), 0) / quizAttemptedRows.length
        )
      : 0;

  // Parse openedAssets once
  const openedAssetsMap: Record<number, string[]> = Object.fromEntries(
    allProgress.map((p) => {
      try { return [p.partNumber, JSON.parse(p.openedAssets as string ?? "[]")]; }
      catch { return [p.partNumber, []]; }
    })
  );

  // Asset counts
  const assetCounts = {
    videos: allProgress.filter((p) => p.videoCompleted).length,
    slides: allProgress.filter((p) => (openedAssetsMap[p.partNumber] ?? []).includes("slides")).length,
    briefings: allProgress.filter((p) => p.briefingOpened).length,
    flashcards: allProgress.filter((p) => p.flashcardsReviewed).length,
    quizzes: allProgress.filter((p) => p.quizPassed).length,
    audio: allProgress.filter((p) => (openedAssetsMap[p.partNumber] ?? []).includes("audio")).length,
    mindmaps: allProgress.filter((p) => (openedAssetsMap[p.partNumber] ?? []).includes("mindmap")).length,
    infographics: allProgress.filter((p) => (openedAssetsMap[p.partNumber] ?? []).includes("infographic")).length,
  };

  // Recent activity — most recently accessed parts with any progress
  const partTitleMap = Object.fromEntries(PARTS.map((p) => [p.partNumber, p.title]));
  const recentParts = allProgress
    .filter((p) => p.lastAccessedAt)
    .sort((a, b) => new Date(b.lastAccessedAt!).getTime() - new Date(a.lastAccessedAt!).getTime())
    .slice(0, 6);

  const stats = [
    { icon: Target, label: "Lessons Completed", value: `${completedCount} / ${TOTAL_PARTS}` },
    { icon: TrendingUp, label: "Progress", value: `${progressPercent}%` },
    { icon: Clock, label: "Study Time", value: formatStudyTime(totalStudySeconds) },
    { icon: Award, label: "Avg Quiz Score", value: avgQuizScore > 0 ? `${avgQuizScore}%` : "—" },
  ];

  return (
    <StudentLayout userPlan={userPlan} userName={user.fullName} activeProfileName={user.activeProfileName} planType={user.planType}>
      <div className="min-h-screen bg-[#0a0a0a]">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <FadeUp className="mb-8">
            <h1 className="text-3xl font-bold text-text mb-1">My Progress</h1>
            <p className="text-text-secondary">
              {profileName}&apos;s learning journey through the Complete Seerah
            </p>
          </FadeUp>

          {/* Top stats */}
          <StaggerChildren className="grid sm:grid-cols-4 gap-4 mb-8" stagger={0.08}>
            {stats.map((stat) => {
              const Icon = stat.icon;
              return (
                <AnimatedCard
                  key={stat.label}
                  lift
                  className="p-6 rounded-xl border border-border bg-surface hover:border-gold/20 transition-colors"
                >
                  <div className="flex items-center gap-3 mb-2">
                    <Icon className="w-5 h-5 text-gold" />
                  </div>
                  <p className="text-text-muted text-sm mb-1">{stat.label}</p>
                  <p className="text-2xl font-bold text-text">{stat.value}</p>
                </AnimatedCard>
              );
            })}
          </StaggerChildren>

          {/* Overall progress bar */}
          <FadeUp className="p-6 rounded-xl border border-border bg-surface mb-8">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-base font-semibold text-text">Overall Completion</h2>
              <span className="text-sm text-gold font-medium">{completedCount} of {TOTAL_PARTS} parts</span>
            </div>
            <div className="h-3 rounded-full bg-surface-raised overflow-hidden">
              <div
                className="h-full rounded-full bg-gradient-to-r from-gold/80 to-gold transition-all duration-700"
                style={{ width: `${progressPercent}%` }}
              />
            </div>
            <p className="text-xs text-text-muted mt-2">
              {inProgressParts.length > 0
                ? `${inProgressParts.length} lesson${inProgressParts.length !== 1 ? "s" : ""} in progress`
                : completedCount === 0
                ? "Start Part 1 to begin tracking your progress"
                : "Keep going — you're making great progress!"}
            </p>
          </FadeUp>

          {/* Asset breakdown */}
          <FadeUp className="p-6 rounded-xl border border-border bg-surface mb-8">
            <h2 className="text-base font-semibold text-text mb-5">Assets Completed</h2>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              {[
                { icon: "🎬", label: "Videos", count: assetCounts.videos },
                { icon: "📄", label: "Briefings", count: assetCounts.briefings },
                { icon: "🗂️", label: "Slides", count: assetCounts.slides },
                { icon: "🃏", label: "Flashcards", count: assetCounts.flashcards },
                { icon: "✅", label: "Quizzes Passed", count: assetCounts.quizzes },
                { icon: "🎧", label: "Audio", count: assetCounts.audio },
                { icon: "🧠", label: "Mindmaps", count: assetCounts.mindmaps },
                { icon: "🖼️", label: "Infographics", count: assetCounts.infographics },
              ].map((asset) => (
                <div key={asset.label} className="flex items-center gap-3 p-3 rounded-lg bg-surface-raised">
                  <span className="text-2xl">{asset.icon}</span>
                  <div>
                    <p className="text-lg font-bold text-text leading-none">{asset.count}</p>
                    <p className="text-xs text-text-muted mt-0.5">{asset.label}</p>
                  </div>
                </div>
              ))}
            </div>
          </FadeUp>

          {/* Recent activity */}
          <FadeUp className="p-6 rounded-xl border border-border bg-surface">
            <h2 className="text-base font-semibold text-text mb-5">Recent Activity</h2>
            {recentParts.length === 0 ? (
              <div className="text-center py-8 text-text-muted">
                <TrendingUp className="w-10 h-10 mx-auto mb-3 opacity-30" />
                <p className="text-sm">No activity yet — start a lesson to see it here</p>
              </div>
            ) : (
              <div className="space-y-2">
                {recentParts.map((p) => {
                  const opened = openedAssetsMap[p.partNumber] ?? [];
                  const done = p.status === "completed" || p.status === "mastered";
                  return (
                    <Link
                      key={p.partNumber}
                      href={`/seerah/part-${p.partNumber}`}
                      className="flex items-center justify-between p-3 rounded-lg bg-surface-raised hover:bg-surface-raised/70 transition-colors group"
                    >
                      <div className="flex items-center gap-3">
                        <span
                          className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold shrink-0 ${
                            done
                              ? "bg-gold/15 text-gold border border-gold/30"
                              : "bg-surface text-text-muted border border-border"
                          }`}
                        >
                          {p.partNumber}
                        </span>
                        <div>
                          <p className="text-sm font-medium text-text leading-snug line-clamp-1">
                            {partTitleMap[p.partNumber] ?? `Part ${p.partNumber}`}
                          </p>
                          <p className="text-xs text-text-muted mt-0.5">
                            {done
                              ? "Completed"
                              : `${p.videoWatchPercent ?? 0}% video · ${opened.length} asset${opened.length !== 1 ? "s" : ""} opened`}
                          </p>
                        </div>
                      </div>
                      <ChevronRight className="w-4 h-4 text-text-muted group-hover:text-text transition-colors shrink-0" />
                    </Link>
                  );
                })}
              </div>
            )}
          </FadeUp>
        </div>
      </div>
    </StudentLayout>
  );
}

