                    <PrefetchPartLink
                      partNumber={stage.firstPartNumber}
                      label={isDone ? "Review" : stage.completedCount > 0 ? "Continue" : "Start"}
                      className={`mt-2 inline-flex items-center gap-1 text-[10px] font-medium transition-colors min-h-[32px] ${
