"use client";

import { useEffect, useCallback, useState } from "react";
import { createPortal } from "react-dom";
import { X, ZoomIn, ZoomOut, RotateCcw } from "lucide-react";

interface ImageLightboxProps {
  src: string;
  alt: string;
  isOpen: boolean;
  onClose: () => void;
}

export function ImageLightbox({ src, alt, isOpen, onClose }: ImageLightboxProps) {
  const [zoom, setZoom] = useState(1);

  const resetZoom = useCallback(() => setZoom(1), []);
  const zoomIn = useCallback(() => setZoom((z) => Math.min(3, parseFloat((z + 0.25).toFixed(2)))), []);
  const zoomOut = useCallback(() => setZoom((z) => Math.max(0.25, parseFloat((z - 0.25).toFixed(2)))), []);

  useEffect(() => {
    if (!isOpen) return;
    setZoom(1);
    const handler = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
      if (e.key === "+" || e.key === "=") zoomIn();
      if (e.key === "-") zoomOut();
      if (e.key === "0") resetZoom();
    };
    document.addEventListener("keydown", handler);
    document.body.style.overflow = "hidden";
    return () => {
      document.removeEventListener("keydown", handler);
      document.body.style.overflow = "";
    };
  }, [isOpen, onClose, zoomIn, zoomOut, resetZoom]);

  if (!isOpen || typeof document === "undefined") return null;

  return createPortal(
    <div
      className="fixed inset-0 z-[100] flex flex-col"
      role="dialog"
      aria-modal="true"
      aria-label={`Image viewer: ${alt}`}
    >
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/92 backdrop-blur-sm"
        onClick={onClose}
      />

      {/* Toolbar */}
      <div className="relative z-10 flex items-center justify-between px-3 py-1.5 flex-shrink-0">
        <p className="text-xs text-white/50 truncate max-w-[50vw]">{alt}</p>
        <div className="flex items-center gap-1">
          <button
            onClick={zoomOut}
            className="min-w-[44px] min-h-[44px] rounded-lg bg-white/10 hover:bg-white/20 border border-white/10 flex items-center justify-center text-white/70 hover:text-white transition-all"
            aria-label="Zoom out"
          >
            <ZoomOut className="w-4 h-4" />
          </button>
          <button
            onClick={resetZoom}
            className="px-2 min-h-[44px] rounded-lg bg-white/10 hover:bg-white/20 border border-white/10 text-xs text-white/70 hover:text-white transition-all tabular-nums min-w-[3.5rem] text-center"
            aria-label={`Reset zoom, currently ${Math.round(zoom * 100)}%`}
          >
            {Math.round(zoom * 100)}%
          </button>
          <button
            onClick={zoomIn}
            className="min-w-[44px] min-h-[44px] rounded-lg bg-white/10 hover:bg-white/20 border border-white/10 flex items-center justify-center text-white/70 hover:text-white transition-all"
            aria-label="Zoom in"
          >
            <ZoomIn className="w-4 h-4" />
          </button>
          <div className="w-px h-5 bg-white/15 mx-1" />
          <button
            onClick={onClose}
            className="min-w-[44px] min-h-[44px] rounded-lg bg-white/10 hover:bg-red-500/30 border border-white/10 hover:border-red-500/30 flex items-center justify-center text-white/70 hover:text-white transition-all"
            aria-label="Close image viewer"
          >
            <X className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Image scroll area */}
      <div
        className="relative flex-1 overflow-auto"
        onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
      >
        <div
          className="flex items-start justify-center min-h-full p-4 pb-8"
          style={{ minWidth: zoom > 1 ? `${zoom * 100}%` : undefined }}
        >
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={src}
            alt={alt}
            style={{
              maxWidth: zoom <= 1 ? "100%" : undefined,
              width: zoom > 1 ? `${zoom * 100}%` : "auto",
              maxHeight: zoom <= 1 ? "calc(100vh - 8rem)" : undefined,
              objectFit: "contain",
              display: "block",
              borderRadius: "0.5rem",
              boxShadow: "0 25px 60px rgba(0,0,0,0.7)",
            }}
            draggable={false}
          />
        </div>
      </div>

      {/* Hint bar */}
      <div className="relative z-10 flex-shrink-0 py-2 text-center">
        <p className="text-[11px] text-white/25">Tap outside to close · Esc · +/− to zoom</p>
      </div>
    </div>,
    document.body
  );
}

import fs from "fs";
import path from "path";
import {
  r2ReadBriefing,
  r2ReadStatementOfFacts,
  r2ReadStudyGuide,
  r2ReadReport,
  r2ReadFlashcards,
  r2ReadQuiz,
  r2GetMindmapKey,
  r2GetInfographicKey,
  r2GetSlideKeys,
  r2GetVideoKey,
  r2GetAudioKey,
  getR2AssetUrl,
  generateSignedR2Url,
  VIDEO_URL_EXPIRY,
  IMAGE_URL_EXPIRY,
} from "./r2";
import { PART_CONTENT } from "./part-content-data";

export const SEERAH_ROOT =
  process.env.SEERAH_DATA_DIR ?? path.resolve(/*turbopackIgnore: true*/ process.cwd(), "..", "Seerah-data");

// Feature flag to use R2 or local filesystem
const USE_R2 = process.env.R2_BUCKET && process.env.R2_ACCESS_KEY_ID;

// ─── Audio ───────────────────────────────────────────────────────────────────
// Check for .mp3 (production format) first, then fall back to .wav (legacy)

export function getAudioFilename(partNum: number): string | null {
  // Check for .mp3 first (production format)
  const mp3 = path.join(SEERAH_ROOT, "Audio", `Part ${partNum}.mp3`);
  if (fs.existsSync(mp3)) return `Part ${partNum}.mp3`;

  // Check for .mp3 with (1) suffix (Windows duplicate naming)
  const mp3WithSuffix = path.join(SEERAH_ROOT, "Audio", `Part ${partNum} (1).mp3`);
  if (fs.existsSync(mp3WithSuffix)) return `Part ${partNum} (1).mp3`;

  // Fallback to .wav files
  const wavWithSuffix = path.join(SEERAH_ROOT, "Audio", `Part ${partNum} (1).wav`);
  if (fs.existsSync(wavWithSuffix)) return `Part ${partNum} (1).wav`;

  const wav = path.join(SEERAH_ROOT, "Audio", `Part ${partNum}.wav`);
  if (fs.existsSync(wav)) return `Part ${partNum}.wav`;

  return null;
}

// ─── Text file reader ─────────────────────────────────────────────────────────

export function readTextFile(filePath: string): string | null {
  try {
    if (!fs.existsSync(filePath)) return null;
    return fs.readFileSync(filePath, "utf-8");
  } catch {
    return null;
  }
}

// ─── Briefing ─────────────────────────────────────────────────────────────────

export async function readBriefing(partNum: number): Promise<string | null> {
  // Return hardcoded content if available (takes priority over R2/filesystem)
  const hardcoded = PART_CONTENT[partNum]?.briefingText;
  if (hardcoded != null) return hardcoded;

  if (USE_R2) {
    return await r2ReadBriefing(partNum);
  }
  const p = path.join(SEERAH_ROOT, "Briefing", `Part ${partNum} Briefing Document.txt`);
  return readTextFile(p);
}

// ─── Statement of Facts ───────────────────────────────────────────────────────

export async function readStatementOfFacts(partNum: number): Promise<string | null> {
  // Return hardcoded content if available (takes priority over R2/filesystem)
  const hardcoded = PART_CONTENT[partNum]?.statementOfFactsText;
  if (hardcoded != null) return hardcoded;

  if (USE_R2) {
    return await r2ReadStatementOfFacts(partNum);
  }
  const p = path.join(SEERAH_ROOT, "StatementOfFacts", `Part ${partNum} - Statement of Facts.txt`);
  return readTextFile(p);
}

// ─── Study Guide ──────────────────────────────────────────────────────────────
// Part 1 is .docx — skip it (no easy server-side docx reader without a dep)

export async function readStudyGuide(partNum: number): Promise<string | null> {
  if (USE_R2) {
    return await r2ReadStudyGuide(partNum);
  }
  const txt = path.join(SEERAH_ROOT, "Studyguides", `Part ${partNum} - Study Guide.txt`);
  if (fs.existsSync(txt)) return readTextFile(txt);

  // .docx exists but we can't parse it without a library — return null for now
  return null;
}

// ─── Report ───────────────────────────────────────────────────────────────────
// Report filenames have variable titles, so we glob the directory

export async function readReport(partNum: number): Promise<string | null> {
  if (USE_R2) {
    return await r2ReadReport(partNum);
  }
  const dir = path.join(SEERAH_ROOT, "Reports");
  try {
    const files = fs.readdirSync(dir);
    const prefix = `Part ${partNum} - Report`;
    const match = files.find(
      (f) => f.startsWith(prefix) && (f.endsWith(".txt") || f.endsWith(".docx"))
    );
    if (!match) return null;
    if (match.endsWith(".docx")) return null; // skip docx without parser
    return readTextFile(path.join(dir, match));
  } catch {
    return null;
  }
}

// ─── Image existence check ────────────────────────────────────────────────────

export async function mindmapExists(partNum: number): Promise<boolean> {
  if (USE_R2) {
    const key = await r2GetMindmapKey(partNum);
    return key !== null;
  }
  return fs.existsSync(path.join(SEERAH_ROOT, "Mindmaps", `Part ${partNum} - Mindmap.png`));
}

/**
 * Infographic filenames differ by style:
 *   Standard/Concise: "Part N - Infographic.png" (sometimes "Part N - Infographic - 2.png" or "Part N - Infographic 2.png")
 *   Bento Grid:       "Part N.png"
 * We scan the directory for the first matching file so naming quirks don't break things.
 * 
 * When using R2, returns the full R2 key (e.g., "Infographics-Bento-Grid/Part 1.png")
 * When using local files, returns just the filename
 */
export async function getInfographicFilename(
  partNum: number,
  style: "Bento Grid" | "Concise" | "Standard"
): Promise<string | null> {
  if (USE_R2) {
    const key = await r2GetInfographicKey(partNum, style);
    return key; // Return full R2 key
  }

  const dir = path.join(SEERAH_ROOT, "Infographics", style);
  try {
    const files = fs.readdirSync(dir);

    if (style === "Bento Grid") {
      return files.find((f) => f === `Part ${partNum}.png`) ?? null;
    }

    // Standard / Concise: strict match first ("Part N - Infographic*.png")
    const strictPrefix = `Part ${partNum} - Infographic`;
    const strictMatch = files.find((f) => f.startsWith(strictPrefix) && f.endsWith(".png"));
    if (strictMatch) return strictMatch;

    // Fallback: some files use non-standard names like "Part N-2.png", "Part N.png",
    // "Part N -2.png", "Part N- Infographic 2.png". Match any PNG that starts with
    // "Part {n}" followed by a non-digit character (prevents Part 4 matching Part 42, etc.)
    const looseRe = new RegExp(`^Part ${partNum}[^0-9]`);
    return files.find((f) => f.endsWith(".png") && looseRe.test(f)) ?? null;
  } catch {
    return null;
  }
}

export async function infographicExists(
  partNum: number,
  style: "Bento Grid" | "Concise" | "Standard"
): Promise<boolean> {
  const filename = await getInfographicFilename(partNum, style);
  return filename !== null;
}

// ─── Slides ───────────────────────────────────────────────────────────────────
// Presented: "Slides - Watermark - Presented/Part 01/" (zero-padded to 2 digits, but 100 is "Part 100")
// Detailed:  "Slides - Watermark - Detailed/Part N Watermark/" (no padding)
// Facts:     "Slides - Watermark - Facts/Part N/" (no padding)

function zeroPad(n: number): string {
  if (n < 10) return `0${n}`;
  return `${n}`;
}

export function getPresentedSlideFolder(partNum: number): string {
  const padded = zeroPad(partNum);
  return path.join(SEERAH_ROOT, "Slides - Watermark - Presented", `Part ${padded}`);
}

export function getDetailedSlideFolder(partNum: number): string {
  return path.join(SEERAH_ROOT, "Slides - Watermark - Detailed", `Part ${partNum} Watermark`);
}

export function getFactsSlideFolder(partNum: number): string {
  return path.join(SEERAH_ROOT, "Slides - Watermark - Facts", `Part ${partNum}`);
}

export type { SlideFile } from "./types";
import type { SlideFile } from "./types";

export async function getSlideFiles(
  partNum: number,
  type: "presented" | "detailed" | "facts"
): Promise<SlideFile[]> {
  if (USE_R2) {
    const pngKeys = await r2GetSlideKeys(partNum, type);
    // Sign the pre-generated WebP variants instead of the raw PNGs.
    // Signed URLs are cryptographically bound to their exact path, so we must sign
    // each variant key individually rather than rewriting URLs on the client.
    return Promise.all(
      pngKeys.map(async (pngKey) => {
        const mediumKey = pngKey.replace(/\.png$/i, "-medium.webp");
        const thumbKey  = pngKey.replace(/\.png$/i, "-thumb.webp");
        const [medium, thumb] = await Promise.all([
          generateSignedR2Url(mediumKey, IMAGE_URL_EXPIRY),
          generateSignedR2Url(thumbKey,  IMAGE_URL_EXPIRY),
        ]);
        return { medium, thumb };
      })
    );
  }

  let folder: string;
  if (type === "presented") folder = getPresentedSlideFolder(partNum);
  else if (type === "detailed") folder = getDetailedSlideFolder(partNum);
  else folder = getFactsSlideFolder(partNum);

  try {
    if (!fs.existsSync(folder)) return [];
    return fs
      .readdirSync(folder)
      .filter((f) => f.endsWith(".png"))
      .sort()
      .map((f) => {
        const rel = path.relative(SEERAH_ROOT, path.join(folder, f));
        const base = `/seerah-media/${rel.replace(/\\/g, "/")}`;
        // Local dev: no WebP variants — use PNG for both
        return { medium: base, thumb: base };
      });
  } catch {
    return [];
  }
}

// ─── Flashcards ───────────────────────────────────────────────────────────────

export async function readFlashcards(partNum: number): Promise<import("./types").FlashcardSet | null> {
  if (USE_R2) {
    return await r2ReadFlashcards(partNum);
  }
  const pad = partNum < 10 ? `0${partNum}` : `${partNum}`;
  const p = path.join(SEERAH_ROOT, "Flashcards", `Part_${pad}.json`);
  try {
    if (!fs.existsSync(p)) return null;
    const raw = fs.readFileSync(p, "utf-8");
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

// ─── Quiz ─────────────────────────────────────────────────────────────────────

export async function readQuiz(partNum: number): Promise<import("./types").Quiz | null> {
  if (USE_R2) {
    return await r2ReadQuiz(partNum);
  }
  const pad = partNum < 10 ? `0${partNum}` : `${partNum}`;
  const p = path.join(SEERAH_ROOT, "Quizzes", `Part_${pad}.json`);
  try {
    if (!fs.existsSync(p)) return null;
    const raw = fs.readFileSync(p, "utf-8");
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

// ─── Video / Audio existence ──────────────────────────────────────────────────

export async function videoExists(partNum: number): Promise<boolean> {
  if (USE_R2) {
    const key = await r2GetVideoKey(partNum);
    return key !== null;
  }
  return fs.existsSync(path.join(SEERAH_ROOT, "Videos", `Part ${partNum}.mp4`));
}

export async function audioExists(partNum: number): Promise<boolean> {
  if (USE_R2) {
    const key = await r2GetAudioKey(partNum);
    return key !== null;
  }
  return getAudioFilename(partNum) !== null;
}

// ─── R2-specific URL helpers ──────────────────────────────────────────────────

/**
 * Get all asset URLs for a part using R2
 */
export async function getPartAssetUrls(partNum: number) {
  if (!USE_R2) {
    // Local dev without R2: use local proxy routes
    return {
      videoUrl: (await videoExists(partNum)) ? `/api/media/video/${partNum}` : undefined,
      audioUrl: (await audioExists(partNum)) ? `/api/media/audio/${partNum}` : undefined,
      mindmapUrl: (await mindmapExists(partNum))
        ? `/seerah-media/Mindmaps/Part ${partNum} - Mindmap.png`
        : undefined,
    };
  }

  const [videoKey, audioKey, mindmapKey] = await Promise.all([
    r2GetVideoKey(partNum),
    r2GetAudioKey(partNum),
    r2GetMindmapKey(partNum),
  ]);

  // All parts — including free Part 1 — use short-lived signed URLs.
  // Access control (free vs paid) is enforced at the page/API level, not via permanent URLs.
  const [videoUrl, audioUrl, mindmapUrl] = await Promise.all([
    videoKey ? generateSignedR2Url(videoKey, VIDEO_URL_EXPIRY) : Promise.resolve(undefined),
    audioKey ? generateSignedR2Url(audioKey, VIDEO_URL_EXPIRY) : Promise.resolve(undefined),
    mindmapKey ? generateSignedR2Url(mindmapKey, IMAGE_URL_EXPIRY) : Promise.resolve(undefined),
  ]);

  return { videoUrl, audioUrl, mindmapUrl };
}

import { createHash, randomBytes } from "crypto";

/** Generate a cryptographically secure 32-byte hex token (64 chars). */
